text:
{
  "formal_minutes": {
    "회의명": "UI Theme Package Release Readiness",
    "프로젝트코드": "PUBLIC_MEETING_SMOKE",
    "참석자": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "항목": "공개 릴리스 목표 시점",
        "내용": "스모크 테스트가 통과하는 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "항목": "packageName mismatch 대응 원칙",
        "내용": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "제안자": "Hara",
        "제안": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경",
        "결론": "거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "항목": "수요일 릴리스",
        "내용": "수요일 릴리스 제안은 내부 스트레치 목표일 뿐이며 확정 일정이 아니다."
      }
    ],
    "non_decisions": [
      {
        "항목": "README 설치 절차 검토",
        "내용": "목요일까지 가능하면 검토하자는 언급은 있었으나 확정 소유자 배정은 없었다."
      }
    ],
    "risks": [
      {
        "항목": "잘못된 tarball 경로",
        "영향": "릴리스 지연 가능"
      },
      {
        "항목": "오래된 README 설치 절차",
        "영향": "릴리스 노트가 사용자에게 오해를 줄 가능성"
      }
    ],
    "open_questions": [
      {
        "질문": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "질문": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 재실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "선행 결과 대기",
      "source_certainty": "confirmed"
    },
    {
      "owner": "미정",
      "task": "README 설치 절차 검토",
      "due": "목요일 가능 시",
      "status": "소유자 미배정",
      "source_certainty": "tentative"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST 기준 Minjun의 스모크 테스트 결과를 확인한다.",
      "금요일 12:00 KST 기준 Doyun의 action_items.md 내 failure triage note 작성 여부를 확인한다.",
      "스모크 결과 공유 이후 Hara의 tarball 경로 점검 결과를 확인한다.",
      "README 설치 절차 검토 담당자 지정 여부를 확인한다.",
      "최종 릴리스 승인 권한자와 릴리스 노트 내 수요일 스트레치 목표 언급 여부를 확인한다."
    ],
    "do_not_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 필요 여부",
      "명시되지 않은 소유자",
      "명시되지 않은 마감시한"
    ]
  },
  "non_invention_rules": {
    "scope_rule": "인라인 공개용 합성 픽스처에 포함된 내용만 사용한다.",
    "fact_boundary": [
      "확정 결정과 거절된 제안을 분리한다.",
      "내부 스트레치 목표를 확정 일정처럼 쓰지 않는다.",
      "리스크와 오픈 질문을 결정사항처럼 쓰지 않는다.",
      "소유자나 마감이 명시되지 않은 항목은 미정으로 둔다."
    ],
    "explicit_non_facts": [
      "고객명 없음",
      "예산 언급 없음",
      "보안 사고 언급 없음",
      "프로덕션 장애 언급 없음",
      "법무 승인 요구 언급 없음"
    ]
  }
}
